    has_x = len(x_positions) > 0
    x_digit = None
    total = 0

    # Determine possible X digits (0-9)
    x_digits = range(10)
    if has_x:
        # If X is in the first position, it can't be 0
        if 0 in x_positions and len(s) > 1:
            x_digits = range(1, 10)
    else:
        x_digits = [None]  # dummy value

    for x_val in x_digits:
        # Replace X with x_val
        temp_s = list(s)
        for pos in x_positions:
            temp_s[pos] = str(x_val) if x_val is not None else 'X'
        temp_s = ''.join(temp_s)

        # Now handle underscores
        underscore_count = temp_s.count('_')
        if underscore_count == 0:
            # Check if the number is valid and divisible by 25
